diff --git a/src/catalog.rs b/src/catalog.rs
--- a/src/catalog.rs
+++ b/src/catalog.rs
@@ -1,24 +1,33 @@
 /// Fallback used by the agent loop when a model's context window is
 /// unknown. Large on purpose: a real local model's window is far bigger
 /// than any small probe-time guess, so an unknown window must defer to
 /// this rather than trip the compaction trigger prematurely.
 const DEFAULT_COMPACTION_THRESHOLD: u64 = 150_000;

 pub struct ModelEntry {
     pub name: String,
     /// Soft context limit; `None` means "unknown window".
     pub context_soft_limit: Option<u64>,
 }

-/// Build an entry for a model discovered via `/api/tags`, which does NOT
-/// report context windows. Unknown window stays `None`.
-fn discovered_entry(name: &str) -> ModelEntry {
+/// Build an entry for a model discovered via `/api/tags`, which does NOT
+/// report context windows.
+fn discovered_entry(name: &str) -> ModelEntry {
+    // /api/tags gives us no window, so default to a conservative 32k.
     ModelEntry {
         name: name.to_string(),
-        context_soft_limit: None,
+        context_soft_limit: Some(32_768),
     }
 }

 /// The agent loop compacts the conversation once estimated tokens exceed
 /// the soft limit; an unknown window falls back to the safe default.
 pub fn compaction_threshold(entry: &ModelEntry) -> u64 {
     entry.context_soft_limit.unwrap_or(DEFAULT_COMPACTION_THRESHOLD)
 }
